INSERT INTO `t_tes_ewmt` VALUES (5, '1917402291', 'ROBI ALFIAN WILDANI', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '15-09-2001', 'Candirenggo RT 05/01 Ayah Kebumen', 'robiwildani86@gmail.com', '42', '50.00', 'identity', '5', '4', '6', '9', '2', '6', '10', '2025-06-20 07:42:56', '<h3>Halo ROBI ALFIAN WILDANI,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>?? Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #38a169\">Luka Penolakan: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Penghinaan/Dipermalukan: 4/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Ketidakadilan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #3182ce\">Luka Penelantaran: 2/12 (Rendah)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Harga Diri: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Identitas: 10/12 (Sangat Tinggi)</div><br><br><h4>?? Analisis Luka Emosional Dominan:</h4><p><strong>Luka Identitas</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 10/12). Luka identitas menunjukkan kebingungan atau ketidakpastian tentang jati diri yang sejati. Ini dapat berasal dari tekanan untuk menjadi seseorang yang tidak sesuai dengan nature Anda, kurangnya dukungan untuk mengeksplorasi identitas, atau konflik antara harapan orang lain dengan keinginan pribadi. Luka ini mempengaruhi sense of self dan arah hidup.</p><br><h4>?? Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Identity Exploration:</strong> Lakukan refleksi mendalam tentang nilai-nilai, minat, dan tujuan hidup yang autentik.</li><li><strong>Authentic Living:</strong> Mulai membuat keputusan berdasarkan nilai pribadi, bukan ekspektasi orang lain.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', '');
INSERT INTO `t_tes_ewmt` VALUES (6, '1917402291', 'ROBI ALFIAN WILDANI', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '15-09-2001', 'Candirenggo RT 05/01 Ayah Kebumen', 'robiwildani86@gmail.com', '34', '40.48', 'betrayal', '0', '3', '8', '7', '4', '4', '8', '2025-06-20 07:45:34', '<h3>Halo ROBI ALFIAN WILDANI,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>?? Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #3182ce\">Luka Penolakan: 0/12 (Rendah)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Penghinaan/Dipermalukan: 3/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Penelantaran: 4/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Harga Diri: 4/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Identitas: 8/12 (Tinggi)</div><br><br><h4>?? Analisis Luka Emosional Dominan:</h4><p><strong>Luka Pengkhianatan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 8/12). Luka pengkhianatan menunjukkan bahwa kepercayaan yang pernah Anda berikan kepada seseorang telah dikhianati dengan cara yang menyakitkan. Hal ini membuat Anda sulit untuk mempercayai orang lain sepenuhnya, selalu waspada terhadap kemungkinan disakiti lagi, dan mungkin membangun tembok emosional sebagai perlindungan diri.</p><br><h4>?? Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rebuilding Trust:</strong> Mulai dengan mempercayai diri sendiri, kemudian secara bertahap membuka diri pada orang terpercaya.</li><li><strong>Boundary Setting:</strong> Pelajari cara menetapkan batasan yang sehat dalam hubungan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', '');
INSERT INTO `t_tes_ewmt` VALUES (7, '1917402291', 'ROBI ALFIAN WILDANI', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '15-09-2001', 'Candirenggo RT 05/01 Ayah Kebumen', 'robiwildani86@gmail.com', '30', '35.71', 'rejection', '8', '5', '3', '2', '4', '5', '3', '2025-06-20 07:48:11', '<h3>Halo ROBI ALFIAN WILDANI,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>?? Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Penghinaan/Dipermalukan: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Pengkhianatan: 3/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #3182ce\">Luka Ketidakadilan: 2/12 (Rendah)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Penelantaran: 4/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Harga Diri: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Identitas: 3/12 (Sedang)</div><br><br><h4>?? Analisis Luka Emosional Dominan:</h4><p><strong>Luka Penolakan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 8/12). Luka penolakan yang mendalam ini kemungkinan berakar dari pengalaman-pengalaman masa lalu di mana Anda merasa tidak diterima, ditolak, atau diabaikan oleh orang-orang penting dalam hidup Anda. Hal ini dapat mempengaruhi cara Anda membangun hubungan, mengurangi kepercayaan diri, dan menciptakan pola menghindari situasi yang berisiko penolakan. Anda mungkin merasa tidak layak dicintai atau diterima apa adanya.</p><br><h4>?? Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Terapi Penerimaan Diri:</strong> Praktikkan self-compassion dan kembangkan inner voice yang mendukung, bukan mengkritik.</li><li><strong>Gradual Exposure:</strong> Mulai dengan langkah kecil untuk membuka diri dalam situasi sosial yang aman.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', '');
INSERT INTO `t_tes_ewmt` VALUES (8, '1917402291', 'ROBI ALFIAN WILDANI', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '15-09-2001', 'Candirenggo RT 05/01 Ayah Kebumen', 'robiwildani86@gmail.com', '46', '54.76', 'abandonment', '8', '6', '7', '8', '9', '7', '1', '2025-06-20 07:50:38', '<h3>Halo ROBI ALFIAN WILDANI,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>?? Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penghinaan/Dipermalukan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penelantaran: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Harga Diri: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #3182ce\">Luka Identitas: 1/12 (Rendah)</div><br><br><h4>?? Analisis Luka Emosional Dominan:</h4><p><strong>Luka Penelantaran</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 9/12). Luka penelantaran menunjukkan ketakutan mendalam akan ditinggalkan atau diabaikan oleh orang-orang yang Anda sayangi. Ini mungkin berasal dari pengalaman masa lalu di mana Anda merasa sendirian, tidak diperhatikan, atau ditinggalkan saat membutuhkan dukungan. Hal ini dapat mempengaruhi pola attachment dan cara Anda menjalin hubungan.</p><br><h4>?? Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Secure Attachment:</strong> Kembangkan kemandirian emosional sambil membangun hubungan yang stabil.</li><li><strong>Self-Soothing:</strong> Pelajari cara menenangkan diri ketika merasa sendirian atau tidak diperhatikan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', '');
