INSERT INTO `t_tes_ewmt` VALUES (24, '0075187420', 'Nailan faza ', '994d7f16-1acd-405d-b744-ddc21791a13d', '27-09-2007', 'Bangsa RT01 RW02 kebasen banyumas ', 'nailanfazafaza@gmail.com', '54', '64.29', '0', '7', '8', '9', '9', '8', '6', '7', '2025-08-20 05:48:31', '<h3>Halo Nailan faza ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penghinaan/Dipermalukan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Ketidakadilan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Harga Diri: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Identitas: 7/12 (Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Pengkhianatan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 9/12). Luka pengkhianatan menunjukkan bahwa kepercayaan yang pernah Anda berikan kepada seseorang telah dikhianati dengan cara yang menyakitkan. Hal ini membuat Anda sulit untuk mempercayai orang lain sepenuhnya, selalu waspada terhadap kemungkinan disakiti lagi, dan mungkin membangun tembok emosional sebagai perlindungan diri.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rebuilding Trust:</strong> Mulai dengan mempercayai diri sendiri, kemudian secara bertahap membuka diri pada orang terpercaya.</li><li><strong>Boundary Setting:</strong> Pelajari cara menetapkan batasan yang sehat dalam hubungan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (25, '425774307', 'MAKIN ALFARUQI', '526ae929-69dc-4719-9ebb-407aefe645fd', '27-03-2008', 'Pubalingga', 'alfaruqimakin@gmail.com', '59', '70.24', '0', '7', '8', '9', '8', '8', '8', '11', '2025-08-20 05:55:23', '<h3>Halo MAKIN ALFARUQI,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penghinaan/Dipermalukan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Harga Diri: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Identitas: 11/12 (Sangat Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Identitas</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 11/12). Luka identitas menunjukkan kebingungan atau ketidakpastian tentang jati diri yang sejati. Ini dapat berasal dari tekanan untuk menjadi seseorang yang tidak sesuai dengan nature Anda, kurangnya dukungan untuk mengeksplorasi identitas, atau konflik antara harapan orang lain dengan keinginan pribadi. Luka ini mempengaruhi sense of self dan arah hidup.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Identity Exploration:</strong> Lakukan refleksi mendalam tentang nilai-nilai, minat, dan tujuan hidup yang autentik.</li><li><strong>Authentic Living:</strong> Mulai membuat keputusan berdasarkan nilai pribadi, bukan ekspektasi orang lain.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (26, '25-3510-030624', 'Hamada Azmi Faruqi', 'c2573df4-489f-490d-ab03-fea6e7076bce', '09-08-2007', 'Pageralang, Kemranjen, Banyumas ', 'hamadaazmi987@gmail.com', '47', '55.95', '0', '6', '8', '7', '6', '7', '5', '8', '2025-08-20 06:06:42', '<h3>Halo Hamada Azmi Faruqi,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penghinaan/Dipermalukan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Harga Diri: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Identitas: 8/12 (Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Penghinaan/Dipermalukan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 8/12). Luka penghinaan yang masih tersimpan ini menunjukkan bahwa pengalaman dipermalukan, dihina, atau direndahkan di masa lalu masih memberikan dampak emosional yang signifikan. Memori tentang rasa malu yang mendalam dapat mempengaruhi harga diri, membuat Anda takut untuk tampil autentik, atau merasa tidak berharga di mata orang lain.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rekonstruksi Self-Worth:</strong> Lakukan afirmasi positif dan tantang pikiran negatif tentang nilai diri Anda.</li><li><strong>Shame Resilience:</strong> Pelajari untuk membedakan antara rasa malu yang sehat dan yang destruktif.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (27, '2502224', 'Hanifah Widya Kholidina Putri ', '6e230978-cd50-4aa1-a702-cb51f3c0ec5e', '24-04-2006', 'Purwojati, Banyumas ', 'hanifahwidya24@gmail.com', '72', '85.71', '0', '11', '11', '8', '11', '10', '10', '11', '2025-08-20 06:22:14', '<h3>Halo Hanifah Widya Kholidina Putri ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penolakan: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penghinaan/Dipermalukan: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Ketidakadilan: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penelantaran: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Harga Diri: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Identitas: 11/12 (Sangat Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Penolakan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 11/12). Luka penolakan yang mendalam ini kemungkinan berakar dari pengalaman-pengalaman masa lalu di mana Anda merasa tidak diterima, ditolak, atau diabaikan oleh orang-orang penting dalam hidup Anda. Hal ini dapat mempengaruhi cara Anda membangun hubungan, mengurangi kepercayaan diri, dan menciptakan pola menghindari situasi yang berisiko penolakan. Anda mungkin merasa tidak layak dicintai atau diterima apa adanya.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Terapi Penerimaan Diri:</strong> Praktikkan self-compassion dan kembangkan inner voice yang mendukung, bukan mengkritik.</li><li><strong>Gradual Exposure:</strong> Mulai dengan langkah kecil untuk membuka diri dalam situasi sosial yang aman.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (28, '2502224', 'Hanifah Widya Kholidina Putri ', '6e230978-cd50-4aa1-a702-cb51f3c0ec5e', '24-08-2025', 'Banyumas ', 'hanifahwidya24@gmail.com', '74', '88.1', '0', '11', '11', '9', '12', '10', '11', '10', '2025-08-20 06:24:49', '<h3>Halo Hanifah Widya Kholidina Putri ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penolakan: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penghinaan/Dipermalukan: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Ketidakadilan: 12/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penelantaran: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Harga Diri: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Identitas: 10/12 (Sangat Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Ketidakadilan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 12/12). Luka ketidakadilan menunjukkan bahwa Anda memiliki memori yang kuat tentang perlakuan yang tidak fair atau adil. Hal ini dapat membuat Anda hipersensitif terhadap ketidakadilan, mudah marah atau frustrasi ketika melihat atau mengalami perlakuan yang tidak setara, dan merasa bahwa hidup tidak memberikan kesempatan yang sama kepada Anda.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Emotional Regulation:</strong> Pelajari teknik mengelola amarah dan frustrasi terhadap ketidakadilan.</li><li><strong>Advocacy Skills:</strong> Kanalkan rasa keadilan menjadi aksi positif untuk perubahan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (29, '425-427-00179', 'wiku anisa puspitasari ', 'ce018e7a-1440-402d-962e-7d92ac52e328', '15-08-2007', 'Cinengan,jalan cinengah kipat,Rt03/05,Pesahangan, cimanggu,kab. Cilacap,Jawa tengah', 'anisapuspita761@gmail.com', '48', '57.14', '0', '6', '6', '7', '9', '9', '5', '6', '2025-08-20 06:33:41', '<h3>Halo wiku anisa puspitasari ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penghinaan/Dipermalukan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Ketidakadilan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penelantaran: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Harga Diri: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Identitas: 6/12 (Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Ketidakadilan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 9/12). Luka ketidakadilan menunjukkan bahwa Anda memiliki memori yang kuat tentang perlakuan yang tidak fair atau adil. Hal ini dapat membuat Anda hipersensitif terhadap ketidakadilan, mudah marah atau frustrasi ketika melihat atau mengalami perlakuan yang tidak setara, dan merasa bahwa hidup tidak memberikan kesempatan yang sama kepada Anda.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Emotional Regulation:</strong> Pelajari teknik mengelola amarah dan frustrasi terhadap ketidakadilan.</li><li><strong>Advocacy Skills:</strong> Kanalkan rasa keadilan menjadi aksi positif untuk perubahan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (30, '0065861353', 'Milda Alda Araminata', '5cee714d-7fb6-4f03-bf2b-0dca3ddb9537', '08-06-2006', 'Dsn.Tarisi Ds.Maruyungsari,Padaherang,Pangandaran', 'mildaalda123@gmail.com', '63', '75', '0', '10', '9', '7', '6', '10', '9', '12', '2025-08-20 06:35:31', '<h3>Halo Milda Alda Araminata,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penolakan: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penghinaan/Dipermalukan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penelantaran: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Harga Diri: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Identitas: 12/12 (Sangat Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Identitas</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 12/12). Luka identitas menunjukkan kebingungan atau ketidakpastian tentang jati diri yang sejati. Ini dapat berasal dari tekanan untuk menjadi seseorang yang tidak sesuai dengan nature Anda, kurangnya dukungan untuk mengeksplorasi identitas, atau konflik antara harapan orang lain dengan keinginan pribadi. Luka ini mempengaruhi sense of self dan arah hidup.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Identity Exploration:</strong> Lakukan refleksi mendalam tentang nilai-nilai, minat, dan tujuan hidup yang autentik.</li><li><strong>Authentic Living:</strong> Mulai membuat keputusan berdasarkan nilai pribadi, bukan ekspektasi orang lain.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (31, '2517110633', 'Yanry Tri Rachmawati ', 'e558be1b-a873-4498-8747-5be1d59ce119', '13-12-2003', 'Sokawera Berkoh ', 'yanryrahmawati42@gmail.com', '68', '80.95', '0', '12', '10', '7', '8', '11', '10', '10', '2025-08-20 06:44:14', '<h3>Halo Yanry Tri Rachmawati ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penolakan: 12/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penghinaan/Dipermalukan: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penelantaran: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Harga Diri: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Identitas: 10/12 (Sangat Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Penolakan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 12/12). Luka penolakan yang mendalam ini kemungkinan berakar dari pengalaman-pengalaman masa lalu di mana Anda merasa tidak diterima, ditolak, atau diabaikan oleh orang-orang penting dalam hidup Anda. Hal ini dapat mempengaruhi cara Anda membangun hubungan, mengurangi kepercayaan diri, dan menciptakan pola menghindari situasi yang berisiko penolakan. Anda mungkin merasa tidak layak dicintai atau diterima apa adanya.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Terapi Penerimaan Diri:</strong> Praktikkan self-compassion dan kembangkan inner voice yang mendukung, bukan mengkritik.</li><li><strong>Gradual Exposure:</strong> Mulai dengan langkah kecil untuk membuka diri dalam situasi sosial yang aman.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (32, '42542700605', 'Candra Maulana Romadhon ', 'c215c529-d923-440a-b340-3147c11ead20', '15-09-2007', 'Paguyangan', 'maulanarcandra@gmail.com', '58', '69.05', '0', '8', '8', '9', '8', '8', '8', '9', '2025-08-20 06:47:32', '<h3>Halo Candra Maulana Romadhon ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penghinaan/Dipermalukan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Harga Diri: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Identitas: 9/12 (Sangat Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Pengkhianatan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 9/12). Luka pengkhianatan menunjukkan bahwa kepercayaan yang pernah Anda berikan kepada seseorang telah dikhianati dengan cara yang menyakitkan. Hal ini membuat Anda sulit untuk mempercayai orang lain sepenuhnya, selalu waspada terhadap kemungkinan disakiti lagi, dan mungkin membangun tembok emosional sebagai perlindungan diri.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rebuilding Trust:</strong> Mulai dengan mempercayai diri sendiri, kemudian secara bertahap membuka diri pada orang terpercaya.</li><li><strong>Boundary Setting:</strong> Pelajari cara menetapkan batasan yang sehat dalam hubungan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (33, '425-427-00641', 'Fhatasya aulia ', '23f06ec3-a59f-4742-ab87-469d8e29452f', '14-04-2005', 'Bengkulu ', 'fhatasyaaulia17@gmail.com', '38', '45.24', '0', '4', '5', '7', '5', '7', '6', '4', '2025-08-20 06:57:08', '<h3>Halo Fhatasya aulia ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #38a169\">Luka Penolakan: 4/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Penghinaan/Dipermalukan: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Ketidakadilan: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Harga Diri: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Identitas: 4/12 (Sedang)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Pengkhianatan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 7/12). Luka pengkhianatan menunjukkan bahwa kepercayaan yang pernah Anda berikan kepada seseorang telah dikhianati dengan cara yang menyakitkan. Hal ini membuat Anda sulit untuk mempercayai orang lain sepenuhnya, selalu waspada terhadap kemungkinan disakiti lagi, dan mungkin membangun tembok emosional sebagai perlindungan diri.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rebuilding Trust:</strong> Mulai dengan mempercayai diri sendiri, kemudian secara bertahap membuka diri pada orang terpercaya.</li><li><strong>Boundary Setting:</strong> Pelajari cara menetapkan batasan yang sehat dalam hubungan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (34, '42542700575', 'Zamira Naila Fahma', 'ce018e7a-1440-402d-962e-7d92ac52e328', '04-11-2006', 'Bandingan RT 03/01, Rakit, Banjarnegara ', 'zamirafahma@gmail.com', '43', '51.19', '0', '7', '7', '8', '5', '6', '4', '6', '2025-08-20 07:03:31', '<h3>Halo Zamira Naila Fahma,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penghinaan/Dipermalukan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Ketidakadilan: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Harga Diri: 4/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Identitas: 6/12 (Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Pengkhianatan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 8/12). Luka pengkhianatan menunjukkan bahwa kepercayaan yang pernah Anda berikan kepada seseorang telah dikhianati dengan cara yang menyakitkan. Hal ini membuat Anda sulit untuk mempercayai orang lain sepenuhnya, selalu waspada terhadap kemungkinan disakiti lagi, dan mungkin membangun tembok emosional sebagai perlindungan diri.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rebuilding Trust:</strong> Mulai dengan mempercayai diri sendiri, kemudian secara bertahap membuka diri pada orang terpercaya.</li><li><strong>Boundary Setting:</strong> Pelajari cara menetapkan batasan yang sehat dalam hubungan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (35, '42542700596', 'Isnaeni Mubarokah ', '01ca1f3d-ea44-4acd-91ca-69fef044657f', '05-12-2006', 'Desa jipang RT 02 RW 03 kec karanglewas kab Banyumas ', 'isnaenimubarokah88@gmail.com', '75', '89.29', '0', '10', '11', '11', '12', '11', '11', '9', '2025-08-20 07:04:06', '<h3>Halo Isnaeni Mubarokah ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penolakan: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penghinaan/Dipermalukan: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Ketidakadilan: 12/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penelantaran: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Harga Diri: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Identitas: 9/12 (Sangat Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Ketidakadilan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 12/12). Luka ketidakadilan menunjukkan bahwa Anda memiliki memori yang kuat tentang perlakuan yang tidak fair atau adil. Hal ini dapat membuat Anda hipersensitif terhadap ketidakadilan, mudah marah atau frustrasi ketika melihat atau mengalami perlakuan yang tidak setara, dan merasa bahwa hidup tidak memberikan kesempatan yang sama kepada Anda.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Emotional Regulation:</strong> Pelajari teknik mengelola amarah dan frustrasi terhadap ketidakadilan.</li><li><strong>Advocacy Skills:</strong> Kanalkan rasa keadilan menjadi aksi positif untuk perubahan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (36, '0065849167', 'Arefa Aulia Putri', '8bacc845-9892-4f14-8d47-4d501286f5d2', '04-11-2006', 'Kembangan', 'arefaputri11@gmail.com', '30', '35.71', '0', '3', '4', '9', '3', '4', '1', '6', '2025-08-20 07:08:44', '<h3>Halo Arefa Aulia Putri,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #38a169\">Luka Penolakan: 3/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Penghinaan/Dipermalukan: 4/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Ketidakadilan: 3/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Penelantaran: 4/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #3182ce\">Luka Harga Diri: 1/12 (Rendah)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Identitas: 6/12 (Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Pengkhianatan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 9/12). Luka pengkhianatan menunjukkan bahwa kepercayaan yang pernah Anda berikan kepada seseorang telah dikhianati dengan cara yang menyakitkan. Hal ini membuat Anda sulit untuk mempercayai orang lain sepenuhnya, selalu waspada terhadap kemungkinan disakiti lagi, dan mungkin membangun tembok emosional sebagai perlindungan diri.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rebuilding Trust:</strong> Mulai dengan mempercayai diri sendiri, kemudian secara bertahap membuka diri pada orang terpercaya.</li><li><strong>Boundary Setting:</strong> Pelajari cara menetapkan batasan yang sehat dalam hubungan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (37, '327603506070001', 'Nadhira maulida', '6d8ce7b0-9375-4e2d-89b9-99f86e0c3867', '13-06-2007', 'Sawangan depok', 'nadhiramaulida62@gmail.com', '54', '64.29', '0', '6', '9', '9', '8', '8', '5', '9', '2025-08-20 07:08:54', '<h3>Halo Nadhira maulida,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penghinaan/Dipermalukan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Harga Diri: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Identitas: 9/12 (Sangat Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Penghinaan/Dipermalukan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 9/12). Luka penghinaan yang masih tersimpan ini menunjukkan bahwa pengalaman dipermalukan, dihina, atau direndahkan di masa lalu masih memberikan dampak emosional yang signifikan. Memori tentang rasa malu yang mendalam dapat mempengaruhi harga diri, membuat Anda takut untuk tampil autentik, atau merasa tidak berharga di mata orang lain.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rekonstruksi Self-Worth:</strong> Lakukan afirmasi positif dan tantang pikiran negatif tentang nilai diri Anda.</li><li><strong>Shame Resilience:</strong> Pelajari untuk membedakan antara rasa malu yang sehat dan yang destruktif.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (38, 'Silvia Rahmadani', 'SILVIA RAHMADANI', '994d7f16-1acd-405d-b744-ddc21791a13d', '13-10-2006', 'Karangbawang RT 5 RW 1, KEC. AJIBARANG, KAB. BANYUMAS', 'rahmadanisilvia827@gmail.com', '40', '47.62', '0', '5', '6', '9', '5', '8', '4', '3', '2025-08-20 07:09:48', '<h3>Halo SILVIA RAHMADANI,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #38a169\">Luka Penolakan: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penghinaan/Dipermalukan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Ketidakadilan: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Harga Diri: 4/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Identitas: 3/12 (Sedang)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Pengkhianatan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 9/12). Luka pengkhianatan menunjukkan bahwa kepercayaan yang pernah Anda berikan kepada seseorang telah dikhianati dengan cara yang menyakitkan. Hal ini membuat Anda sulit untuk mempercayai orang lain sepenuhnya, selalu waspada terhadap kemungkinan disakiti lagi, dan mungkin membangun tembok emosional sebagai perlindungan diri.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rebuilding Trust:</strong> Mulai dengan mempercayai diri sendiri, kemudian secara bertahap membuka diri pada orang terpercaya.</li><li><strong>Boundary Setting:</strong> Pelajari cara menetapkan batasan yang sehat dalam hubungan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (39, '42542700593', 'Ibnu Setiawan', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '03-02-2007', 'Desa Pliken, Kecamatan Kembaran, Banyumas', 'ibnustwn123@gmail.com', '48', '57.14', '0', '6', '8', '11', '7', '6', '5', '5', '2025-08-20 07:13:20', '<h3>Halo Ibnu Setiawan,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penghinaan/Dipermalukan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Harga Diri: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Identitas: 5/12 (Sedang)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Pengkhianatan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 11/12). Luka pengkhianatan menunjukkan bahwa kepercayaan yang pernah Anda berikan kepada seseorang telah dikhianati dengan cara yang menyakitkan. Hal ini membuat Anda sulit untuk mempercayai orang lain sepenuhnya, selalu waspada terhadap kemungkinan disakiti lagi, dan mungkin membangun tembok emosional sebagai perlindungan diri.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rebuilding Trust:</strong> Mulai dengan mempercayai diri sendiri, kemudian secara bertahap membuka diri pada orang terpercaya.</li><li><strong>Boundary Setting:</strong> Pelajari cara menetapkan batasan yang sehat dalam hubungan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (40, '0061936287', 'Nanda Rosa Agustina ', 'ce018e7a-1440-402d-962e-7d92ac52e328', '24-08-2006', 'nandanandarosaagustina@gmail.com', 'nandanandarosaagustina@gamil.com', '27', '32.14', '0', '3', '3', '6', '3', '6', '3', '3', '2025-08-20 07:23:42', '<h3>Halo Nanda Rosa Agustina ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #38a169\">Luka Penolakan: 3/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Penghinaan/Dipermalukan: 3/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Ketidakadilan: 3/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Harga Diri: 3/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Identitas: 3/12 (Sedang)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Pengkhianatan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 6/12). Luka pengkhianatan menunjukkan bahwa kepercayaan yang pernah Anda berikan kepada seseorang telah dikhianati dengan cara yang menyakitkan. Hal ini membuat Anda sulit untuk mempercayai orang lain sepenuhnya, selalu waspada terhadap kemungkinan disakiti lagi, dan mungkin membangun tembok emosional sebagai perlindungan diri.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rebuilding Trust:</strong> Mulai dengan mempercayai diri sendiri, kemudian secara bertahap membuka diri pada orang terpercaya.</li><li><strong>Boundary Setting:</strong> Pelajari cara menetapkan batasan yang sehat dalam hubungan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (41, '12512700592', 'Amanta Azaria ', 'c215c529-d923-440a-b340-3147c11ead20', '13-06-2007', 'Karang Klesem RT 01 RW 01 Purwokerto Selatan ', 'amantaazaria277@gmail.com', '36', '42.86', '0', '2', '5', '7', '5', '8', '5', '4', '2025-08-20 07:40:39', '<h3>Halo Amanta Azaria ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #3182ce\">Luka Penolakan: 2/12 (Rendah)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Penghinaan/Dipermalukan: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Ketidakadilan: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Harga Diri: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Identitas: 4/12 (Sedang)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Penelantaran</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 8/12). Luka penelantaran menunjukkan ketakutan mendalam akan ditinggalkan atau diabaikan oleh orang-orang yang Anda sayangi. Ini mungkin berasal dari pengalaman masa lalu di mana Anda merasa sendirian, tidak diperhatikan, atau ditinggalkan saat membutuhkan dukungan. Hal ini dapat mempengaruhi pola attachment dan cara Anda menjalin hubungan.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Secure Attachment:</strong> Kembangkan kemandirian emosional sambil membangun hubungan yang stabil.</li><li><strong>Self-Soothing:</strong> Pelajari cara menenangkan diri ketika merasa sendirian atau tidak diperhatikan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (42, '42542700604', 'Maulida Haura Syauq', '8162d095-2244-4fca-8561-5b63f375bd5b', '02-04-2007', 'Purwokerto', 'maulidahaura35@gmail.com', '55', '65.48', '0', '10', '8', '9', '9', '8', '5', '6', '2025-08-20 07:44:26', '<h3>Halo Maulida Haura Syauq,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penolakan: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penghinaan/Dipermalukan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Ketidakadilan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Harga Diri: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Identitas: 6/12 (Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Penolakan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 10/12). Luka penolakan yang mendalam ini kemungkinan berakar dari pengalaman-pengalaman masa lalu di mana Anda merasa tidak diterima, ditolak, atau diabaikan oleh orang-orang penting dalam hidup Anda. Hal ini dapat mempengaruhi cara Anda membangun hubungan, mengurangi kepercayaan diri, dan menciptakan pola menghindari situasi yang berisiko penolakan. Anda mungkin merasa tidak layak dicintai atau diterima apa adanya.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Terapi Penerimaan Diri:</strong> Praktikkan self-compassion dan kembangkan inner voice yang mendukung, bukan mengkritik.</li><li><strong>Gradual Exposure:</strong> Mulai dengan langkah kecil untuk membuka diri dalam situasi sosial yang aman.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (43, '0069585652', 'Wahda Atiyya Fauzi', 'a09d4718-2359-408f-ae43-93afd060f839', '17-06-2006', 'Wonosobo', 'atiyyawahda@gmail.com', '61', '72.62', '0', '10', '8', '8', '10', '8', '9', '8', '2025-08-20 07:46:56', '<h3>Halo Wahda Atiyya Fauzi,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penolakan: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penghinaan/Dipermalukan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Ketidakadilan: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Harga Diri: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Identitas: 8/12 (Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Penolakan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 10/12). Luka penolakan yang mendalam ini kemungkinan berakar dari pengalaman-pengalaman masa lalu di mana Anda merasa tidak diterima, ditolak, atau diabaikan oleh orang-orang penting dalam hidup Anda. Hal ini dapat mempengaruhi cara Anda membangun hubungan, mengurangi kepercayaan diri, dan menciptakan pola menghindari situasi yang berisiko penolakan. Anda mungkin merasa tidak layak dicintai atau diterima apa adanya.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Terapi Penerimaan Diri:</strong> Praktikkan self-compassion dan kembangkan inner voice yang mendukung, bukan mengkritik.</li><li><strong>Gradual Exposure:</strong> Mulai dengan langkah kecil untuk membuka diri dalam situasi sosial yang aman.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (44, '2502303', 'Rizqina Zuleyka ', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '08-05-2007', 'Karanggude rt 03/04,Baleraksa,karangmoncol,Purbalingga,Jawa Tengah', 'rizqinazuleyka@gmail.com', '53', '63.1', '0', '10', '6', '10', '6', '4', '9', '8', '2025-08-20 07:51:32', '<h3>Halo Rizqina Zuleyka ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penolakan: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penghinaan/Dipermalukan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Penelantaran: 4/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Harga Diri: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Identitas: 8/12 (Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Penolakan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 10/12). Luka penolakan yang mendalam ini kemungkinan berakar dari pengalaman-pengalaman masa lalu di mana Anda merasa tidak diterima, ditolak, atau diabaikan oleh orang-orang penting dalam hidup Anda. Hal ini dapat mempengaruhi cara Anda membangun hubungan, mengurangi kepercayaan diri, dan menciptakan pola menghindari situasi yang berisiko penolakan. Anda mungkin merasa tidak layak dicintai atau diterima apa adanya.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Terapi Penerimaan Diri:</strong> Praktikkan self-compassion dan kembangkan inner voice yang mendukung, bukan mengkritik.</li><li><strong>Gradual Exposure:</strong> Mulai dengan langkah kecil untuk membuka diri dalam situasi sosial yang aman.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (45, '0066867637', 'MUHAMAD NABIL ALFARIZI ', 'a09d4718-2359-408f-ae43-93afd060f839', '04-11-2006', 'Desa SIDAURIP Rt 05 RW 02 kecamatan Gandrungmangu kabupaten Cilacap ', 'farisbaru8@gmail.com', '78', '92.86', '0', '9', '11', '11', '12', '12', '11', '12', '2025-08-20 07:58:32', '<h3>Halo MUHAMAD NABIL ALFARIZI ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penolakan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penghinaan/Dipermalukan: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Ketidakadilan: 12/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penelantaran: 12/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Harga Diri: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Identitas: 12/12 (Sangat Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Ketidakadilan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 12/12). Luka ketidakadilan menunjukkan bahwa Anda memiliki memori yang kuat tentang perlakuan yang tidak fair atau adil. Hal ini dapat membuat Anda hipersensitif terhadap ketidakadilan, mudah marah atau frustrasi ketika melihat atau mengalami perlakuan yang tidak setara, dan merasa bahwa hidup tidak memberikan kesempatan yang sama kepada Anda.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Emotional Regulation:</strong> Pelajari teknik mengelola amarah dan frustrasi terhadap ketidakadilan.</li><li><strong>Advocacy Skills:</strong> Kanalkan rasa keadilan menjadi aksi positif untuk perubahan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (46, '425-427-01257', 'AGRA ALISATUL INAYAH', 'ea6e129b-2302-4951-afc8-a3676d110608', '06-08-2006', 'Cikawung Rt3 Rw4 Pekuncen,Banyumas', 'agraalisaa@gmail.com', '45', '53.57', '0', '5', '8', '10', '6', '7', '4', '5', '2025-08-20 08:01:45', '<h3>Halo AGRA ALISATUL INAYAH,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #38a169\">Luka Penolakan: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penghinaan/Dipermalukan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Harga Diri: 4/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Identitas: 5/12 (Sedang)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Pengkhianatan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 10/12). Luka pengkhianatan menunjukkan bahwa kepercayaan yang pernah Anda berikan kepada seseorang telah dikhianati dengan cara yang menyakitkan. Hal ini membuat Anda sulit untuk mempercayai orang lain sepenuhnya, selalu waspada terhadap kemungkinan disakiti lagi, dan mungkin membangun tembok emosional sebagai perlindungan diri.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rebuilding Trust:</strong> Mulai dengan mempercayai diri sendiri, kemudian secara bertahap membuka diri pada orang terpercaya.</li><li><strong>Boundary Setting:</strong> Pelajari cara menetapkan batasan yang sehat dalam hubungan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (47, '3327020607070003', 'Khoerul syafik ', '63bbc719-bef9-4643-b4a1-234af87a6b8d', '06-07-2007', 'RT 01 RW 05 Desa Clekatakan kecamatan Pulosari Kab Pemalang ', 'khoerulsafik@gmail.com', '52', '61.9', '0', '7', '9', '7', '7', '9', '7', '6', '2025-08-20 08:07:22', '<h3>Halo Khoerul syafik ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penghinaan/Dipermalukan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penelantaran: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Harga Diri: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Identitas: 6/12 (Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Penghinaan/Dipermalukan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 9/12). Luka penghinaan yang masih tersimpan ini menunjukkan bahwa pengalaman dipermalukan, dihina, atau direndahkan di masa lalu masih memberikan dampak emosional yang signifikan. Memori tentang rasa malu yang mendalam dapat mempengaruhi harga diri, membuat Anda takut untuk tampil autentik, atau merasa tidak berharga di mata orang lain.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rekonstruksi Self-Worth:</strong> Lakukan afirmasi positif dan tantang pikiran negatif tentang nilai diri Anda.</li><li><strong>Shame Resilience:</strong> Pelajari untuk membedakan antara rasa malu yang sehat dan yang destruktif.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (48, '42542700720', 'Makhya Anjana', 'ce018e7a-1440-402d-962e-7d92ac52e328', '02-06-2007', 'Dondong kesugihan cilacap', 'anjanamakhya05@gmail.com', '64', '76.19', '0', '9', '11', '10', '9', '11', '6', '8', '2025-08-20 08:08:35', '<h3>Halo Makhya Anjana,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penolakan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penghinaan/Dipermalukan: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Ketidakadilan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penelantaran: 11/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Harga Diri: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Identitas: 8/12 (Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Penghinaan/Dipermalukan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 11/12). Luka penghinaan yang masih tersimpan ini menunjukkan bahwa pengalaman dipermalukan, dihina, atau direndahkan di masa lalu masih memberikan dampak emosional yang signifikan. Memori tentang rasa malu yang mendalam dapat mempengaruhi harga diri, membuat Anda takut untuk tampil autentik, atau merasa tidak berharga di mata orang lain.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rekonstruksi Self-Worth:</strong> Lakukan afirmasi positif dan tantang pikiran negatif tentang nilai diri Anda.</li><li><strong>Shame Resilience:</strong> Pelajari untuk membedakan antara rasa malu yang sehat dan yang destruktif.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (49, '2500520149', 'Sifa Wulan sari', 'ce018e7a-1440-402d-962e-7d92ac52e328', '25-12-2006', 'tasikmalaya', 'sifawulansari01@gmail.com', '48', '57.14', '0', '8', '6', '10', '4', '8', '6', '6', '2025-08-20 08:12:56', '<h3>Halo Sifa Wulan sari,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penghinaan/Dipermalukan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Ketidakadilan: 4/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Harga Diri: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Identitas: 6/12 (Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Pengkhianatan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 10/12). Luka pengkhianatan menunjukkan bahwa kepercayaan yang pernah Anda berikan kepada seseorang telah dikhianati dengan cara yang menyakitkan. Hal ini membuat Anda sulit untuk mempercayai orang lain sepenuhnya, selalu waspada terhadap kemungkinan disakiti lagi, dan mungkin membangun tembok emosional sebagai perlindungan diri.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rebuilding Trust:</strong> Mulai dengan mempercayai diri sendiri, kemudian secara bertahap membuka diri pada orang terpercaya.</li><li><strong>Boundary Setting:</strong> Pelajari cara menetapkan batasan yang sehat dalam hubungan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (50, '42542701421', 'Tantri Ardina Kumalasari ', 'a09d4718-2359-408f-ae43-93afd060f839', '06-01-2007', 'Wangon, Banyumas ', 'tantriardinakumalasari@gmail.com', '42', '50', '0', '7', '4', '6', '7', '7', '5', '6', '2025-08-20 08:20:48', '<h3>Halo Tantri Ardina Kumalasari ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Penghinaan/Dipermalukan: 4/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Harga Diri: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Identitas: 6/12 (Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Penolakan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 7/12). Luka penolakan yang mendalam ini kemungkinan berakar dari pengalaman-pengalaman masa lalu di mana Anda merasa tidak diterima, ditolak, atau diabaikan oleh orang-orang penting dalam hidup Anda. Hal ini dapat mempengaruhi cara Anda membangun hubungan, mengurangi kepercayaan diri, dan menciptakan pola menghindari situasi yang berisiko penolakan. Anda mungkin merasa tidak layak dicintai atau diterima apa adanya.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Terapi Penerimaan Diri:</strong> Praktikkan self-compassion dan kembangkan inner voice yang mendukung, bukan mengkritik.</li><li><strong>Gradual Exposure:</strong> Mulai dengan langkah kecil untuk membuka diri dalam situasi sosial yang aman.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (51, '0076895320', 'Noor Iskandar Rachmat Aziz ', 'ce018e7a-1440-402d-962e-7d92ac52e328', '04-09-2007', 'Cikalong Sidareja Cilacap ', 'nooriskandarra79@gmail.com', '62', '73.81', '0', '9', '9', '10', '7', '8', '9', '10', '2025-08-20 08:23:52', '<h3>Halo Noor Iskandar Rachmat Aziz ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penolakan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penghinaan/Dipermalukan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 10/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Harga Diri: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Identitas: 10/12 (Sangat Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Pengkhianatan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 10/12). Luka pengkhianatan menunjukkan bahwa kepercayaan yang pernah Anda berikan kepada seseorang telah dikhianati dengan cara yang menyakitkan. Hal ini membuat Anda sulit untuk mempercayai orang lain sepenuhnya, selalu waspada terhadap kemungkinan disakiti lagi, dan mungkin membangun tembok emosional sebagai perlindungan diri.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rebuilding Trust:</strong> Mulai dengan mempercayai diri sendiri, kemudian secara bertahap membuka diri pada orang terpercaya.</li><li><strong>Boundary Setting:</strong> Pelajari cara menetapkan batasan yang sehat dalam hubungan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
