INSERT INTO `t_tes_ewmt` VALUES (258, '2517110266', 'risna safinatun najah ', 'a09d4718-2359-408f-ae43-93afd060f839', '02-05-2007', 'grujugan kemranjen Banyumas ', 'risnasafina3@gmail.com', '44', '52.38', '0', '7', '5', '9', '8', '7', '5', '3', '2025-08-22 14:36:13', '<h3>Halo risna safinatun najah ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Penghinaan/Dipermalukan: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Pengkhianatan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Harga Diri: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Identitas: 3/12 (Sedang)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Pengkhianatan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 9/12). Luka pengkhianatan menunjukkan bahwa kepercayaan yang pernah Anda berikan kepada seseorang telah dikhianati dengan cara yang menyakitkan. Hal ini membuat Anda sulit untuk mempercayai orang lain sepenuhnya, selalu waspada terhadap kemungkinan disakiti lagi, dan mungkin membangun tembok emosional sebagai perlindungan diri.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rebuilding Trust:</strong> Mulai dengan mempercayai diri sendiri, kemudian secara bertahap membuka diri pada orang terpercaya.</li><li><strong>Boundary Setting:</strong> Pelajari cara menetapkan batasan yang sehat dalam hubungan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (259, '42542700829', 'enjelina trihapsari ', '6d8ce7b0-9375-4e2d-89b9-99f86e0c3867', '22-03-2007', 'bantarsari ', 'hapsariangelin@gmail.com', '38', '45.24', '0', '5', '5', '6', '6', '8', '3', '5', '2025-08-22 14:41:29', '<h3>Halo enjelina trihapsari ,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #38a169\">Luka Penolakan: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Penghinaan/Dipermalukan: 5/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Harga Diri: 3/12 (Sedang)</div><div class=\"wound-score\" style=\"background: #38a169\">Luka Identitas: 5/12 (Sedang)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Penelantaran</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 8/12). Luka penelantaran menunjukkan ketakutan mendalam akan ditinggalkan atau diabaikan oleh orang-orang yang Anda sayangi. Ini mungkin berasal dari pengalaman masa lalu di mana Anda merasa sendirian, tidak diperhatikan, atau ditinggalkan saat membutuhkan dukungan. Hal ini dapat mempengaruhi pola attachment dan cara Anda menjalin hubungan.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Secure Attachment:</strong> Kembangkan kemandirian emosional sambil membangun hubungan yang stabil.</li><li><strong>Self-Soothing:</strong> Pelajari cara menenangkan diri ketika merasa sendirian atau tidak diperhatikan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (260, '2517110824', 'Fuad Jauhari Nafis', '23f06ec3-a59f-4742-ab87-469d8e29452f', '29-04-2007', 'Kav. Bumi Mandiri blok H 1, Kab. Bekasi', 'fuadjauhari61@gmail.com', '54', '64.29', '0', '7', '9', '6', '7', '7', '9', '9', '2025-08-22 14:46:14', '<h3>Halo Fuad Jauhari Nafis,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Penghinaan/Dipermalukan: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Harga Diri: 9/12 (Sangat Tinggi)</div><div class=\"wound-score\" style=\"background: #e53e3e\">Luka Identitas: 9/12 (Sangat Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Penghinaan/Dipermalukan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 9/12). Luka penghinaan yang masih tersimpan ini menunjukkan bahwa pengalaman dipermalukan, dihina, atau direndahkan di masa lalu masih memberikan dampak emosional yang signifikan. Memori tentang rasa malu yang mendalam dapat mempengaruhi harga diri, membuat Anda takut untuk tampil autentik, atau merasa tidak berharga di mata orang lain.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rekonstruksi Self-Worth:</strong> Lakukan afirmasi positif dan tantang pikiran negatif tentang nilai diri Anda.</li><li><strong>Shame Resilience:</strong> Pelajari untuk membedakan antara rasa malu yang sehat dan yang destruktif.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
INSERT INTO `t_tes_ewmt` VALUES (261, '42542700538', 'Asfa Aristiana', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '08-08-2007', 'Pemalang ', 'asfaaristiana@gmail.com', '51', '60.71', '0', '6', '7', '8', '8', '7', '8', '7', '2025-08-22 14:46:42', '<h3>Halo Asfa Aristiana,</h3><p>Berdasarkan hasil EWMT Anda, berikut adalah analisis mendalam tentang luka emosional yang masih mempengaruhi hidup Anda:</p><br><h4>Skor per Kategori Luka Emosional:</h4><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penolakan: 6/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penghinaan/Dipermalukan: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Pengkhianatan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Ketidakadilan: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Penelantaran: 7/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Harga Diri: 8/12 (Tinggi)</div><div class=\"wound-score\" style=\"background: #dd6b20\">Luka Identitas: 7/12 (Tinggi)</div><br><br><h4>Analisis Luka Emosional Dominan:</h4><p><strong>Luka Pengkhianatan</strong> merupakan luka emosional yang paling dominan dalam memori dan pengalaman Anda saat ini (skor: 8/12). Luka pengkhianatan menunjukkan bahwa kepercayaan yang pernah Anda berikan kepada seseorang telah dikhianati dengan cara yang menyakitkan. Hal ini membuat Anda sulit untuk mempercayai orang lain sepenuhnya, selalu waspada terhadap kemungkinan disakiti lagi, dan mungkin membangun tembok emosional sebagai perlindungan diri.</p><br><h4>Rekomendasi Penyembuhan & Pengembangan:</h4><ol style=\"text-align: left; padding-left: 20px;\"><li><strong>Rebuilding Trust:</strong> Mulai dengan mempercayai diri sendiri, kemudian secara bertahap membuka diri pada orang terpercaya.</li><li><strong>Boundary Setting:</strong> Pelajari cara menetapkan batasan yang sehat dalam hubungan.</li><li><strong>Terapi Profesional:</strong> Pertimbangkan konseling dengan psikolog yang berpengalaman dalam trauma dan attachment therapy.</li><li><strong>EMDR atau Somatic Therapy:</strong> Untuk memproses memori traumatis yang tersimpan dalam tubuh.</li><li><strong>Mindfulness & Meditasi:</strong> Praktikkan kesadaran diri untuk mengenali trigger dan pola emosional.</li><li><strong>Support System:</strong> Bangun jaringan dukungan dengan orang-orang yang understanding dan supportive.</li><li><strong>Journaling Therapy:</strong> Tulis jurnal untuk memproses emosi dan melihat pola-pola yang berulang.</li></ol><br><p><em><strong>Catatan Penting:</strong> Proses penyembuhan luka emosional adalah journey yang membutuhkan waktu, kesabaran, dan self-compassion. Setiap langkah kecil yang Anda ambil adalah kemajuan yang berarti. Ingatlah bahwa memiliki luka emosional bukan berarti Anda \"rusak\" - ini adalah bagian dari pengalaman manusia yang dapat disembuhkan dan menjadi sumber kekuatan.</em></p>', 'baru');
