INSERT INTO `t_tes_kepribadian` VALUES (17, 224110503054, 'MOHAMAD IQBAL MUDIAH', '97886710-6e84-42e6-8872-62e1e3034c5c', '28-04-2003', 'Penyalahan', 'rxking135ccspekporting@gmail.com', 'Analytical Leader', 'Creative Collaborator', 'Kinesthetic', 'Auditory', 'Sosial', 'Bisnis', 'Prestasi', 'Kebebasan', 'Jagakarsa adalah sebuah kecamatan di Jakarta Selatan yang terdiri dari beberapa kelurahan, termasuk Kelurahan Jagakarsa itu sendiri. Kelurahan Jagakarsa memiliki kode pos 12620 dan berbatasan dengan beberapa wilayah lain, seperti Kebagusan, Cilandak, Ciganjur, dan kota Depok. Kecamatan Jagakarsa memiliki luas wilayah 25,01 km² dan jumlah penduduk sekitar 222.004 jiwa. ', 'Kawasan Menteng yang mewah merupakan tempat bagi lokasi pertunjukan musik live dan lounge koktail berkelas, dan monumen Selamat Datang yang terkenal. Tempat makan bernuansa santai berderet di Jalan Sabang, menyajikan makanan seperti sup ayam pedas dan sate. Kompleks seni Taman Ismail Marzuki (TIM) menawarkan pertunjukan tari kontemporer dan pameran kesenian modern, sedangkan Taman Menteng memiliki rumah kaca yang kini menampilkan pameran foto', '2025-06-19 08:56:09.382228', NULL);
INSERT INTO `t_tes_kepribadian` VALUES (18, 1917402084, 'ANNISAAUL AZIIZAH', '97886710-6e84-42e6-8872-62e1e3034c5c', '04-05-2001', 'ADIMULYO, RT 2 RW 03 KABUPATEN KEBUMEN', 'Uhnc3622@gmail.com', 'Analytical Leader', 'Creative Collaborator', 'Kinesthetic', 'Auditory', 'Teknologi', 'Sosial', 'Kebebasan', 'Spiritualitas', 'Jagakarsa adalah sebuah kecamatan di Jakarta Selatan yang terdiri dari beberapa kelurahan, termasuk Kelurahan Jagakarsa itu sendiri. Kelurahan Jagakarsa memiliki kode pos 12620 dan berbatasan dengan beberapa wilayah lain, seperti Kebagusan, Cilandak, Ciganjur, dan kota Depok. Kecamatan Jagakarsa memiliki luas wilayah 25,01 km² dan jumlah penduduk sekitar 222.004 jiwa. ', 'Kawasan Menteng yang mewah merupakan tempat bagi lokasi pertunjukan musik live dan lounge koktail berkelas, dan monumen Selamat Datang yang terkenal. Tempat makan bernuansa santai berderet di Jalan Sabang, menyajikan makanan seperti sup ayam pedas dan sate. Kompleks seni Taman Ismail Marzuki (TIM) menawarkan pertunjukan tari kontemporer dan pameran kesenian modern, sedangkan Taman Menteng memiliki rumah kaca yang kini menampilkan pameran foto', '2025-06-20 02:54:24.360585', NULL);
INSERT INTO `t_tes_kepribadian` VALUES (19, 1917402084, 'ANNISAAUL AZIIZAH', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '04-05-2001', 'ADIMULYO, RT 2 RW 03 KABUPATEN KEBUMEN', 'Uhnc3622@gmail.com', 'Creative Collaborator', 'Analytical Leader', 'Kinesthetic', 'Visual', 'Sosial', 'Teknologi', 'Spiritualitas', 'Kebebasan', 'Sebagai kombinasi Creative Collaborator dan Analytical Leader, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Kinesthetic dan Visual, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Sosial dan Teknologi membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Spiritualitas dan Kebebasan, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Sosial dan Teknologi untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Sosial dan Teknologi.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Kinesthetic dan Visual untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Spiritualitas dan Kebebasan dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-06-20 06:19:39.940368', NULL);
INSERT INTO `t_tes_kepribadian` VALUES (20, 1917402291, 'ROBI ALFIAN WILDANI', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '15-09-2001', 'Candirenggo RT 05/01 Ayah Kebumen', 'robiwildani86@gmail.com', 'Analytical Leader', 'Creative Collaborator', 'Visual', 'Auditory', 'Sosial', 'Teknologi', 'Kebebasan', 'Prestasi', 'Sebagai kombinasi Analytical Leader dan Creative Collaborator, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Visual dan Auditory, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Sosial dan Teknologi membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Kebebasan dan Prestasi, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Sosial dan Teknologi untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Sosial dan Teknologi.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Visual dan Auditory untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Kebebasan dan Prestasi dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-06-20 06:55:37.690617', NULL);
INSERT INTO `t_tes_kepribadian` VALUES (21, 1717402008, 'DEA ANANDA NUR FAJAR', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '19-03-1999', 'Jalan Pahlawan Tanjung Purwokerto selatan banyumas', 'deaanandanurfajar1919@gmail.co', 'Creative Collaborator', 'Independent Innovator', 'Kinesthetic', 'Visual', 'Sosial', 'Bisnis', 'Kebebasan', 'Prestasi', 'Sebagai kombinasi Creative Collaborator dan Independent Innovator, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Kinesthetic dan Visual, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Sosial dan Bisnis membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Kebebasan dan Prestasi, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Sosial dan Bisnis untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Sosial dan Bisnis.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Kinesthetic dan Visual untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Kebebasan dan Prestasi dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-06-24 02:41:37.538352', NULL);
