INSERT INTO `t_tes_kepribadian` VALUES (146, 2517110053, 'Nanda Dwi Aprilia ', '6e230978-cd50-4aa1-a702-cb51f3c0ec5e', '18-04-2007', 'Kedungmalang Rt01 02 ', 'nandaprili00@gmail.com', 'Analytical Leader', 'Creative Collaborator', 'Auditory', 'Visual', 'Sosial', 'Teknologi', 'Kebebasan', 'Prestasi', 'Sebagai kombinasi Analytical Leader dan Creative Collaborator, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Auditory dan Visual, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Sosial dan Teknologi membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Kebebasan dan Prestasi, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Sosial dan Teknologi untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Sosial dan Teknologi.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Auditory dan Visual untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Kebebasan dan Prestasi dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-08-20 10:04:05.012151', 'baru');
