INSERT INTO `t_tes_kepribadian` VALUES (266, 63820687, 'PUTRI LATHIFA ALIYYA ZAHRA', '8162d095-2244-4fca-8561-5b63f375bd5b', '08-11-2006', 'KLAMPOK RT 04 RW 10 BANJARNEGARA JAWA TENGAH', 'aliyyaputri33@gmail.com', 'Analytical Leader', 'Creative Collaborator', 'Kinesthetic', 'Visual', 'Sosial', 'Bisnis', 'Prestasi', 'Spiritualitas', 'Sebagai kombinasi Analytical Leader dan Creative Collaborator, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Kinesthetic dan Visual, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Sosial dan Bisnis membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Prestasi dan Spiritualitas, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Sosial dan Bisnis untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Sosial dan Bisnis.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Kinesthetic dan Visual untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Prestasi dan Spiritualitas dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-08-20 15:25:45.595513', 'baru');
INSERT INTO `t_tes_kepribadian` VALUES (267, 3304064909060001, 'Keisya elita', '6d8ce7b0-9375-4e2d-89b9-99f86e0c3867', '09-09-2006', 'cendana rt 02 rw 01 kec banjarnegara kab. banjarnegara', 'keiysaelita@gmail.com', 'Creative Collaborator', 'Analytical Leader', 'Visual', 'Auditory', 'Teknologi', 'Bisnis', 'Spiritualitas', 'Kebebasan', 'Sebagai kombinasi Creative Collaborator dan Analytical Leader, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Visual dan Auditory, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Teknologi dan Bisnis membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Spiritualitas dan Kebebasan, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Teknologi dan Bisnis untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Teknologi dan Bisnis.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Visual dan Auditory untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Spiritualitas dan Kebebasan dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-08-20 15:27:20.894046', 'baru');
