INSERT INTO `t_tes_kepribadian` VALUES (304, 66472726, 'Pramitha Sudiyolinarti Hafith ', '63bbc719-bef9-4643-b4a1-234af87a6b8d', '02-12-2006', 'Ds. Talok RT 02/RW 01, kec. Pangkah, kan. Tegal', 'mithaa060@gmail.com', 'Analytical Leader', 'Creative Collaborator', 'Auditory', 'Kinesthetic', 'Sosial', 'Teknologi', 'Spiritualitas', 'Kebebasan', 'Sebagai kombinasi Analytical Leader dan Creative Collaborator, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Auditory dan Kinesthetic, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Sosial dan Teknologi membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Spiritualitas dan Kebebasan, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Sosial dan Teknologi untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Sosial dan Teknologi.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Auditory dan Kinesthetic untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Spiritualitas dan Kebebasan dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-08-20 21:51:13.286881', 'baru');
INSERT INTO `t_tes_kepribadian` VALUES (305, 74789867, 'Fara Qamilatun Audilla', 'c215c529-d923-440a-b340-3147c11ead20', '23-03-2007', 'Desa Pondok Gebangsari RT 03/ RW 01', 'retnoisti30@gmail.com', 'Analytical Leader', 'Creative Collaborator', 'Visual', 'Auditory', 'Bisnis', 'Sosial', 'Spiritualitas', 'Prestasi', 'Sebagai kombinasi Analytical Leader dan Creative Collaborator, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Visual dan Auditory, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Bisnis dan Sosial membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Spiritualitas dan Prestasi, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Bisnis dan Sosial untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Bisnis dan Sosial.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Visual dan Auditory untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Spiritualitas dan Prestasi dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-08-20 22:30:11.352784', 'baru');
