INSERT INTO `t_tes_kepribadian` VALUES (367, 65472782, 'Hibatulloh zuhri', '994d7f16-1acd-405d-b744-ddc21791a13d', '22-09-2006', 'Grecol, kalimanah, purbalingga', 'hibatullohzhii@gmail.com', 'Analytical Leader', 'Creative Collaborator', 'Kinesthetic', 'Auditory', 'Teknologi', 'Sosial', 'Kebebasan', 'Prestasi', 'Sebagai kombinasi Analytical Leader dan Creative Collaborator, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Kinesthetic dan Auditory, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Teknologi dan Sosial membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Kebebasan dan Prestasi, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Teknologi dan Sosial untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Teknologi dan Sosial.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Kinesthetic dan Auditory untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Kebebasan dan Prestasi dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-08-21 04:13:06.346304', 'baru');
INSERT INTO `t_tes_kepribadian` VALUES (368, 72104992, 'Khalyla Inta Hapsafellah ', '23f06ec3-a59f-4742-ab87-469d8e29452f', '09-05-2007', 'Jakarta Timur', 'scarlettsenclovazca@gmail.com', 'Independent Innovator', 'Analytical Leader', 'Visual', 'Auditory', 'Sosial', 'Teknologi', 'Kebebasan', 'Spiritualitas', 'Sebagai kombinasi Independent Innovator dan Analytical Leader, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Visual dan Auditory, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Sosial dan Teknologi membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Kebebasan dan Spiritualitas, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Sosial dan Teknologi untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Sosial dan Teknologi.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Visual dan Auditory untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Kebebasan dan Spiritualitas dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-08-21 04:24:18.619355', 'baru');
