INSERT INTO `t_tes_kepribadian` VALUES (543, 64988592, 'Intan Nur Janatun Solehah ', '591d453d-0976-40c5-863c-9e1cac0c78b9', '07-06-2006', 'Dki jakarta ', 'intansolehah76@sma.belajar.id', 'Creative Collaborator', 'Analytical Leader', 'Visual', 'Auditory', 'Sosial', 'Teknologi', 'Prestasi', 'Spiritualitas', 'Sebagai kombinasi Creative Collaborator dan Analytical Leader, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Visual dan Auditory, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Sosial dan Teknologi membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Prestasi dan Spiritualitas, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Sosial dan Teknologi untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Sosial dan Teknologi.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Visual dan Auditory untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Prestasi dan Spiritualitas dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-08-22 05:44:32.307082', 'baru');
INSERT INTO `t_tes_kepribadian` VALUES (544, 78070092, 'alicia puspita pradini', '8bacc845-9892-4f14-8d47-4d501286f5d2', '18-07-2007', 'cilacap, binangun', 'aliciapuspita27@gmail.com', 'Analytical Leader', 'Creative Collaborator', 'Visual', 'Auditory', 'Sosial', 'Teknologi', 'Prestasi', 'Spiritualitas', 'Sebagai kombinasi Analytical Leader dan Creative Collaborator, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Visual dan Auditory, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Sosial dan Teknologi membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Prestasi dan Spiritualitas, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Sosial dan Teknologi untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Sosial dan Teknologi.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Visual dan Auditory untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Prestasi dan Spiritualitas dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-08-22 05:46:37.570212', 'baru');
