INSERT INTO `t_tes_kepribadian` VALUES (659, 254110201287, 'Nayla Luthfia Syafanah ', '63bbc719-bef9-4643-b4a1-234af87a6b8d', '22-11-2006', 'CANDIWULAN RT 12 RW 05, KEC. KUTASARI, KAB. PURBALINGGA', 'naylasafanah0@gmail.com', 'Creative Collaborator', 'Independent Innovator', 'Auditory', 'Visual', 'Sosial', 'Bisnis', 'Prestasi', 'Kebebasan', 'Sebagai kombinasi Creative Collaborator dan Independent Innovator, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Auditory dan Visual, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Sosial dan Bisnis membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Prestasi dan Kebebasan, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Sosial dan Bisnis untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Sosial dan Bisnis.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Auditory dan Visual untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Prestasi dan Kebebasan dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-08-24 03:12:42.944384', 'baru');
INSERT INTO `t_tes_kepribadian` VALUES (660, 2544110402268, 'Mega ayu Chandra Kirana ', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '11-11-2006', 'Jl sultan Hassanudin RT 04/rw02,Tegal selatan ,kota tegal', 'megaayucandrakirana@gmail.com', 'Analytical Leader', 'Creative Collaborator', 'Kinesthetic', 'Visual', 'Sosial', 'Teknologi', 'Kebebasan', 'Prestasi', 'Sebagai kombinasi Analytical Leader dan Creative Collaborator, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Kinesthetic dan Visual, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Sosial dan Teknologi membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Kebebasan dan Prestasi, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Sosial dan Teknologi untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Sosial dan Teknologi.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Kinesthetic dan Visual untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Kebebasan dan Prestasi dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-08-24 03:24:28.390869', 'baru');
