INSERT INTO `t_tes_kepribadian` VALUES (708, 254110601097, 'Anggit Nudiono Khaerulloh', 'd637a1a8-e2f9-4e7a-8b45-8683ddf8b4f5', '01-08-2006', 'Karangsari, klontong RT 05 RW 03, Kec.punggelan, Kab.Banjarnegara', 'anggitkhaerulloh@gmail.com', 'Creative Collaborator', 'Independent Innovator', 'Kinesthetic', 'Auditory', 'Sosial', 'Teknologi', 'Kebebasan', 'Prestasi', 'Sebagai kombinasi Creative Collaborator dan Independent Innovator, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Kinesthetic dan Auditory, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Sosial dan Teknologi membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Kebebasan dan Prestasi, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Sosial dan Teknologi untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Sosial dan Teknologi.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Kinesthetic dan Auditory untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Kebebasan dan Prestasi dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-08-25 06:59:00.204895', 'baru');
