INSERT INTO `t_tes_kepribadian` VALUES (715, 254110202124, 'Novita eka febriyani', 'c215c529-d923-440a-b340-3147c11ead20', '08-02-2008', 'Kaliwedi,kebasen,banyumas', 'novitaekafebriyani910@gmail.com', 'Analytical Leader', 'Independent Innovator', 'Auditory', 'Visual', 'Sosial', 'Teknologi', 'Prestasi', 'Spiritualitas', 'Sebagai kombinasi Analytical Leader dan Independent Innovator, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Auditory dan Visual, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Sosial dan Teknologi membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Prestasi dan Spiritualitas, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Sosial dan Teknologi untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Sosial dan Teknologi.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Auditory dan Visual untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Prestasi dan Spiritualitas dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-08-25 12:51:05.912716', 'baru');
INSERT INTO `t_tes_kepribadian` VALUES (716, 254110601059, 'Diah Ayu Aulianingrum ', 'd637a1a8-e2f9-4e7a-8b45-8683ddf8b4f5', '16-06-2007', 'Kedungpring RT 05 RW 03, kec. Kemranjen, kan. Banyumas ', 'ningrumdiyah271@gmail.com', 'Creative Collaborator', 'Analytical Leader', 'Visual', 'Kinesthetic', 'Bisnis', 'Sosial', 'Prestasi', 'Spiritualitas', 'Sebagai kombinasi Creative Collaborator dan Analytical Leader, Anda menunjukkan kecenderungan kuat dalam menghadapi tantangan dan bekerja sama dalam berbagai situasi. Gaya belajar dominan Anda, yaitu Visual dan Kinesthetic, memperlihatkan bagaimana Anda paling efektif dalam menyerap dan mengolah informasi. Minat besar Anda di bidang Bisnis dan Sosial membuka peluang untuk berkembang di sektor-sektor strategis. Nilai hidup utama Anda, Prestasi dan Spiritualitas, menjadi bahan bakar dan arah dalam perjalanan Anda. Penting untuk menjaga fleksibilitas dan keterbukaan terhadap perubahan agar potensi ini semakin maksimal.', '<p style=\"margin-bottom: 10px;\"><strong>1.</strong> Fokuskan pengembangan di bidang Bisnis dan Sosial untuk mengoptimalkan potensi Anda.</p><p style=\"margin-bottom: 10px;\"><strong>2.</strong> Perkaya pengalaman Anda dengan mengikuti pelatihan dan kursus yang sesuai dengan bidang minat Anda.</p><p style=\"margin-bottom: 10px;\"><strong>3.</strong> Bangun relasi profesional dengan para praktisi di bidang Bisnis dan Sosial.</p><p style=\"margin-bottom: 10px;\"><strong>4.</strong> Asah keahlian berbasis gaya belajar Visual dan Kinesthetic untuk meningkatkan efektivitas dalam menguasai keterampilan baru.</p><p style=\"margin-bottom: 10px;\"><strong>5.</strong> Tetaplah setia pada nilai hidup Prestasi dan Spiritualitas dalam mengambil keputusan karier.</p><p style=\"margin-bottom: 10px;\"><strong>6.</strong> Terus perluas wawasan dan pengetahuan untuk mendukung perkembangan karier dan kehidupan yang bermakna.</p>', '2025-08-25 12:54:01.125827', 'baru');
