INSERT INTO `t_tes_lvih` VALUES (36, 12512700592, 'Amanta Azaria ', 'c215c529-d923-440a-b340-3147c11ead20', '13-06-2007', 'Karang Klesem RT 01 RW 01 Purwokerto Selatan ', 'amantaazaria277@gmail.com', '43', '100', '43', 'Sedang', 'Strategi Coping', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-20 07:34:26', 'baru');
INSERT INTO `t_tes_lvih` VALUES (37, 42542700604, 'Maulida Haura Syauq', '8162d095-2244-4fca-8561-5b63f375bd5b', '02-04-2007', 'Purwokerto', 'maulidahaura35@gmail.com', '64', '100', '64', 'Tinggi', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-20 07:40:31', 'baru');
INSERT INTO `t_tes_lvih` VALUES (38, 69585652, 'Wahda Atiyya Fauzi', 'a09d4718-2359-408f-ae43-93afd060f839', '17-06-2006', 'Wonosobo', 'atiyyawahda@gmail.com', '90', '100', '90', 'Sangat Tinggi', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang sangat tinggi. Perasaan terisolasi dan terputus dari orang lain kemungkinan menjadi pengalaman yang dominan dan menyulitkan dalam hidup Anda saat ini. Penting untuk menyadari bahwa tingkat kerentanan ini bukanlah refleksi dari nilai diri Anda, tetapi merupakan hasil dari berbagai faktor yang dapat ditangani dengan dukungan dan strategi yang tepat.', 'Pertimbangkan untuk berkonsultasi dengan psikolog atau terapis yang dapat membantu Anda mengembangkan keterampilan sosial dan mengatasi pola pikir negatif | Bergabunglah dengan kelompok terapi atau support group untuk kesepian, yang memberikan ruang aman untuk berbagi pengalaman dan belajar dari orang lain | Tetapkan tujuan kecil namun terukur untuk interaksi sosial, seperti menghadiri satu acara sosial per minggu atau mengajak percakapan dengan satu orang baru | Praktikkan mindfulness dan self-compassion untuk mengurangi dialog internal negatif yang dapat mengisolasi Anda | Batasi penggunaan media sosial dan tingkatkan interaksi tatap muka yang bermakna | Eksplorasi terapi kognitif perilaku (CBT) untuk menantang dan mengubah pola pikir yang meningkatkan kesepian | Pertimbangkan konseling keluarga jika masalah kesepian Anda berakar pada dinamika keluarga | Jaga keseimbangan antara kebutuhan untuk waktu sendiri dan koneksi sosial yang bermakna', '2025-08-20 07:43:19', 'baru');
