INSERT INTO `t_tes_lvih` VALUES (72, 67471363, 'Desti Zulfa Ananta', '5cee714d-7fb6-4f03-bf2b-0dca3ddb9537', '18-12-2006', 'Kutawuluh Blimbing rt 06 rw 03 kec. Purwonegoro, kab. Banjarnegara', 'zulfaananta1812@gmail.com', '64', '100', '64', 'Tinggi', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-20 11:59:01', 'baru');
INSERT INTO `t_tes_lvih` VALUES (73, 2502056, 'Nur farchatul fatichah', '63bbc719-bef9-4643-b4a1-234af87a6b8d', '05-03-2007', 'duku mursyid randudongkal pemalang', 'farhahimoezt05@gmail.com', '87', '100', '87', 'Sangat Tinggi', 'Faktor Kepribadian', 'Anda memiliki tingkat kerentanan kesepian yang sangat tinggi. Perasaan terisolasi dan terputus dari orang lain kemungkinan menjadi pengalaman yang dominan dan menyulitkan dalam hidup Anda saat ini. Penting untuk menyadari bahwa tingkat kerentanan ini bukanlah refleksi dari nilai diri Anda, tetapi merupakan hasil dari berbagai faktor yang dapat ditangani dengan dukungan dan strategi yang tepat.', 'Pertimbangkan untuk berkonsultasi dengan psikolog atau terapis yang dapat membantu Anda mengembangkan keterampilan sosial dan mengatasi pola pikir negatif | Bergabunglah dengan kelompok terapi atau support group untuk kesepian, yang memberikan ruang aman untuk berbagi pengalaman dan belajar dari orang lain | Tetapkan tujuan kecil namun terukur untuk interaksi sosial, seperti menghadiri satu acara sosial per minggu atau mengajak percakapan dengan satu orang baru | Praktikkan mindfulness dan self-compassion untuk mengurangi dialog internal negatif yang dapat mengisolasi Anda | Batasi penggunaan media sosial dan tingkatkan interaksi tatap muka yang bermakna | Eksplorasi terapi kognitif perilaku (CBT) untuk menantang dan mengubah pola pikir yang meningkatkan kesepian | Pertimbangkan konseling keluarga jika masalah kesepian Anda berakar pada dinamika keluarga | Jaga keseimbangan antara kebutuhan untuk waktu sendiri dan koneksi sosial yang bermakna', '2025-08-20 12:00:45', 'baru');
INSERT INTO `t_tes_lvih` VALUES (74, 3073906713, 'Ulvatul Laila ', 'c215c529-d923-440a-b340-3147c11ead20', '09-04-2007', 'Kebumen ', 'ulvatullaila@gmail.com', '42', '100', '42', 'Sedang', 'Strategi Coping', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-20 12:01:11', 'baru');
INSERT INTO `t_tes_lvih` VALUES (75, 2501108, 'KAILA UHTIA AMALIA ZAHRO', 'a09d4718-2359-408f-ae43-93afd060f839', '10-08-2007', 'Kedungwringin RT 04 RW 03', 'kaylaukhtiaamaliazahra@gmail.com', '57', '100', '57', 'Sedang', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-20 12:01:13', 'baru');
INSERT INTO `t_tes_lvih` VALUES (76, 72177494, 'KHALAWATUN NAJWA ', '5cee714d-7fb6-4f03-bf2b-0dca3ddb9537', '01-11-2006', 'Jl. Jurusan Jatibarang Balapulang Wetan RT.03 RW.04 Kec.Balapulang Kab.Tegal', 'najwabzpiaww@gmail.com', '37', '100', '37', 'Rendah-Sedang', 'Strategi Coping', 'Anda memiliki tingkat kerentanan kesepian yang rendah hingga sedang. Anda kemungkinan besar memiliki sistem dukungan sosial yang cukup baik dan kemampuan untuk membentuk koneksi bermakna. Meskipun Anda mungkin mengalami kesepian sesekali, ini biasanya sementara dan dapat diatasi dengan strategi yang efektif.', 'Pertahankan dan pelihara jaringan dukungan sosial yang sudah Anda miliki | Jadilah proaktif dalam mengatur pertemuan sosial, jangan menunggu orang lain untuk berinisiatif | Jelajahi cara-cara untuk memperdalam koneksi yang sudah ada melalui kegiatan bersama dan percakapan yang lebih bermakna | Kembangkan kapasitas untuk menikmati waktu sendiri tanpa merasa kesepian | Berbagi keterampilan dan strategi sosial Anda dengan orang lain yang mungkin berjuang dengan kesepian | Periksa kembali keseimbangan kehidupan digital Anda untuk memastikan tidak menggantikan koneksi tatap muka | Cari peluang untuk koneksi antar generasi, yang dapat memperkaya perspektif sosial Anda | Praktikkan rasa syukur untuk hubungan yang berharga dalam hidup Anda', '2025-08-20 12:08:41', 'baru');
INSERT INTO `t_tes_lvih` VALUES (77, 2517110714, 'Haidar Alif Zakaria ', '994d7f16-1acd-405d-b744-ddc21791a13d', '08-01-2007', 'jalan pahlawan Tanjung gang 5', 'haidaralifzakaria@gmail.com', '77', '100', '77', 'Tinggi', 'Strategi Coping', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-20 12:09:37', 'baru');
INSERT INTO `t_tes_lvih` VALUES (78, 2501038, 'Mukhammad Ngabid Ngadani', '01ca1f3d-ea44-4acd-91ca-69fef044657f', '07-06-2006', 'Pagerandong Rt03 Rw04 kec. Mrebet kab. Purbalingga', 'ngabidngadani@gmail.com', '51', '100', '51', 'Sedang', 'Faktor Kepribadian', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-20 12:21:06', 'baru');
