INSERT INTO `t_tes_lvih` VALUES (88, 73159778, 'Valda Fidela Mahes Wari', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '23-07-2007', 'Desa plangkapan rt 05/02 kec tambak kab banyumas', 'valdafidela0@gmail.com', '75', '100', '75', 'Tinggi', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-20 12:53:12', 'baru');
INSERT INTO `t_tes_lvih` VALUES (89, 2502398, 'Haitsuma Abqori', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '05-11-2005', 'Pemalang Jawa tengah', 'arrislenteng@gmail.com', '62', '100', '62', 'Tinggi', 'Strategi Coping', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-20 12:53:54', 'baru');
INSERT INTO `t_tes_lvih` VALUES (90, 2502259, 'Azwa Rifa Karista ', 'ea6e129b-2302-4951-afc8-a3676d110608', '05-09-2007', 'Banyumas ', 'azwa.rifakarista@gmail.com', '51', '100', '51', 'Sedang', 'Strategi Coping', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-20 12:57:35', 'baru');
INSERT INTO `t_tes_lvih` VALUES (91, 74415579, 'Dewi Anjani', '5cee714d-7fb6-4f03-bf2b-0dca3ddb9537', '04-01-2007', 'Kab. Kebumen, kec. Buluspesantren, ds. Tanjungrejo', 'anjani.njann@gmail.com', '59', '100', '59', 'Sedang', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-20 12:58:12', 'baru');
INSERT INTO `t_tes_lvih` VALUES (92, 42542700688, 'Ainun Ismatun Najwa ', '591d453d-0976-40c5-863c-9e1cac0c78b9', '06-07-2006', 'Desa sanggreman kecamatan Rawalo kabupaten Banyumas ', 'aismatunnajwa@gmail.com', '82', '100', '82', 'Sangat Tinggi', 'Strategi Coping', 'Anda memiliki tingkat kerentanan kesepian yang sangat tinggi. Perasaan terisolasi dan terputus dari orang lain kemungkinan menjadi pengalaman yang dominan dan menyulitkan dalam hidup Anda saat ini. Penting untuk menyadari bahwa tingkat kerentanan ini bukanlah refleksi dari nilai diri Anda, tetapi merupakan hasil dari berbagai faktor yang dapat ditangani dengan dukungan dan strategi yang tepat.', 'Pertimbangkan untuk berkonsultasi dengan psikolog atau terapis yang dapat membantu Anda mengembangkan keterampilan sosial dan mengatasi pola pikir negatif | Bergabunglah dengan kelompok terapi atau support group untuk kesepian, yang memberikan ruang aman untuk berbagi pengalaman dan belajar dari orang lain | Tetapkan tujuan kecil namun terukur untuk interaksi sosial, seperti menghadiri satu acara sosial per minggu atau mengajak percakapan dengan satu orang baru | Praktikkan mindfulness dan self-compassion untuk mengurangi dialog internal negatif yang dapat mengisolasi Anda | Batasi penggunaan media sosial dan tingkatkan interaksi tatap muka yang bermakna | Eksplorasi terapi kognitif perilaku (CBT) untuk menantang dan mengubah pola pikir yang meningkatkan kesepian | Pertimbangkan konseling keluarga jika masalah kesepian Anda berakar pada dinamika keluarga | Jaga keseimbangan antara kebutuhan untuk waktu sendiri dan koneksi sosial yang bermakna', '2025-08-20 13:07:16', 'baru');
INSERT INTO `t_tes_lvih` VALUES (93, 63165120, 'Balqis Zaharatussifa ', '139cbf79-5ef8-4a08-a58a-9b1fb8c76da6', '21-12-2006', 'Kabupaten Tegal ', 'zaharatussifabalqis@gmail.com', '50', '100', '50', 'Sedang', 'Strategi Coping', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-20 13:07:44', 'baru');
