INSERT INTO `t_tes_lvih` VALUES (134, 71757101, 'Alfin Najmi Saba\\\'ah ', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '26-02-2007', 'Pekaja, RT 07/03, Kalibagor-Banyumas ', 'alfinnajmi531@gmail.com', '52', '100', '52', 'Sedang', 'Strategi Coping', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-21 00:13:31', 'baru');
INSERT INTO `t_tes_lvih` VALUES (135, 253510120029, 'Awalia Arumasikha ', '526ae929-69dc-4719-9ebb-407aefe645fd', '18-09-2006', 'Banjarnegara ', 'aarumasikha@gmail.com', '64', '100', '64', 'Tinggi', 'Pengalaman Masa Kecil', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-21 00:13:39', 'baru');
