INSERT INTO `t_tes_lvih` VALUES (144, 63345351, 'sofa fawazullaila', '8162d095-2244-4fca-8561-5b63f375bd5b', '06-04-2006', 'Kp. margamulya, Rt.006/Rw.001, Desa. cikondang, Kec. Cineam, Kab. Tasikmalaya', 'sofafawazullaila@gmail.com', '66', '100', '66', 'Tinggi', 'Pengalaman Masa Kecil', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-21 01:12:55', 'baru');
INSERT INTO `t_tes_lvih` VALUES (145, 77001122, 'Endah Durrotul Jannah ', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '09-06-2007', 'Jl.Cokronegoro RT 05 RW 02,Purwadadi,Nusawungu,Cilacap', 'endahh2020@gmail.com', '62', '100', '62', 'Tinggi', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-21 01:14:04', 'baru');
INSERT INTO `t_tes_lvih` VALUES (146, 425001277, 'Rizki Maulana Ramadhan ', 'd637a1a8-e2f9-4e7a-8b45-8683ddf8b4f5', '06-10-2006', 'Perum Mulawarman Blok G No 6, RT 04 RW 01, Karangklesem, Purwokerto Selatan ', 'rizkimaulana1148@gmail.com', '37', '100', '37', 'Rendah-Sedang', 'Faktor Kepribadian', 'Anda memiliki tingkat kerentanan kesepian yang rendah hingga sedang. Anda kemungkinan besar memiliki sistem dukungan sosial yang cukup baik dan kemampuan untuk membentuk koneksi bermakna. Meskipun Anda mungkin mengalami kesepian sesekali, ini biasanya sementara dan dapat diatasi dengan strategi yang efektif.', 'Pertahankan dan pelihara jaringan dukungan sosial yang sudah Anda miliki | Jadilah proaktif dalam mengatur pertemuan sosial, jangan menunggu orang lain untuk berinisiatif | Jelajahi cara-cara untuk memperdalam koneksi yang sudah ada melalui kegiatan bersama dan percakapan yang lebih bermakna | Kembangkan kapasitas untuk menikmati waktu sendiri tanpa merasa kesepian | Berbagi keterampilan dan strategi sosial Anda dengan orang lain yang mungkin berjuang dengan kesepian | Periksa kembali keseimbangan kehidupan digital Anda untuk memastikan tidak menggantikan koneksi tatap muka | Cari peluang untuk koneksi antar generasi, yang dapat memperkaya perspektif sosial Anda | Praktikkan rasa syukur untuk hubungan yang berharga dalam hidup Anda', '2025-08-21 01:16:24', 'baru');
INSERT INTO `t_tes_lvih` VALUES (147, 72202845, 'Nasah Nur Buchari ', '6d8ce7b0-9375-4e2d-89b9-99f86e0c3867', '09-07-2007', 'Krajan RT 02 RW 06 , Kec.Pekuncen Kab.Banyumas', 'nasyahnur743@gmail.com', '56', '100', '56', 'Sedang', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-21 01:41:42', 'baru');
INSERT INTO `t_tes_lvih` VALUES (148, 2504023, 'Naufal muhyiddin', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '04-09-2004', 'Desa kedungarum kec/kab.kuningan', 'novalmuhyidin876@gmail.com', '67', '100', '67', 'Tinggi', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-21 01:44:56', 'baru');
INSERT INTO `t_tes_lvih` VALUES (149, 75462790, 'faridatun khasanah ', '6d8ce7b0-9375-4e2d-89b9-99f86e0c3867', '14-09-2007', 'Jatisari, dk. Jatisalam RT 13 RW 03 Kec Kebumen Kab Kebumen', 'faridahasanah805@gmail.com', '66', '100', '66', 'Tinggi', 'Faktor Kepribadian', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-21 02:02:48', 'baru');
