INSERT INTO `t_tes_lvih` VALUES (188, 67349032, 'Selvi Setianingtyas', '23f06ec3-a59f-4742-ab87-469d8e29452f', '11-04-2006', 'Tajug 02/02 Karangmoncol Purbalingga', 'selvisetianingtyas11@gmail.com', '51', '100', '51', 'Sedang', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-21 07:30:45', 'baru');
