INSERT INTO `t_tes_lvih` VALUES (202, 42503270, 'Ni\\\'matul Azizah ', '97886710-6e84-42e6-8872-62e1e3034c5c', '08-07-2006', 'DS.korowelang RT/RW 003/002 kec.supang kab.remabng', 'azizahnikmah29@gmail.com', '61', '100', '61', 'Tinggi', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-21 08:23:23', 'baru');
INSERT INTO `t_tes_lvih` VALUES (203, 79827077, 'Amelia salsabila ', '8162d095-2244-4fca-8561-5b63f375bd5b', '03-05-2007', 'Dusun jepang krawang sari RT 003/RW 001 Natar Lampung Selatan ', 'salsabilaamel04@gmail.com', '22', '100', '22', 'Rendah-Sedang', 'Faktor Kepribadian', 'Anda memiliki tingkat kerentanan kesepian yang rendah hingga sedang. Anda kemungkinan besar memiliki sistem dukungan sosial yang cukup baik dan kemampuan untuk membentuk koneksi bermakna. Meskipun Anda mungkin mengalami kesepian sesekali, ini biasanya sementara dan dapat diatasi dengan strategi yang efektif.', 'Pertahankan dan pelihara jaringan dukungan sosial yang sudah Anda miliki | Jadilah proaktif dalam mengatur pertemuan sosial, jangan menunggu orang lain untuk berinisiatif | Jelajahi cara-cara untuk memperdalam koneksi yang sudah ada melalui kegiatan bersama dan percakapan yang lebih bermakna | Kembangkan kapasitas untuk menikmati waktu sendiri tanpa merasa kesepian | Berbagi keterampilan dan strategi sosial Anda dengan orang lain yang mungkin berjuang dengan kesepian | Periksa kembali keseimbangan kehidupan digital Anda untuk memastikan tidak menggantikan koneksi tatap muka | Cari peluang untuk koneksi antar generasi, yang dapat memperkaya perspektif sosial Anda | Praktikkan rasa syukur untuk hubungan yang berharga dalam hidup Anda', '2025-08-21 08:31:50', 'baru');
INSERT INTO `t_tes_lvih` VALUES (204, 72352109, 'Dewi kusnaeni', '6d8ce7b0-9375-4e2d-89b9-99f86e0c3867', '13-08-2007', 'Desa Sidanegara rt10 RW 06 kecamatan Kedungreja kabupaten Cilacap cilacap', 'dewikusnaeni2@gmail.com', '68', '100', '68', 'Tinggi', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-21 08:43:08', 'baru');
