INSERT INTO `t_tes_lvih` VALUES (206, 79950724, 'DWI INDAH SAPUTRI ', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '27-07-2007', 'Gentasari Bayeman kidul rt 12 rw 03 ', 'dwisaputriindah07@gmail.com', '48', '100', '48', 'Sedang', 'Strategi Coping', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-21 08:51:04', 'baru');
INSERT INTO `t_tes_lvih` VALUES (207, 2504005, 'Natasya Agustina Putri', 'f4e73fa4-f4ec-4c47-8552-b6f01036b77d', '09-08-2006', 'Jalan ks tubun rt 8 rw 3,Bobosan,Purwokerto Utara,Banyumas,Jawa Tengah', 'natasyagustinaputri@gmail.com', '53', '100', '53', 'Sedang', 'Faktor Kepribadian', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-21 09:22:38', 'baru');
INSERT INTO `t_tes_lvih` VALUES (208, 63886081, 'Mu\\\'iz Afifudin', '6d8ce7b0-9375-4e2d-89b9-99f86e0c3867', '06-07-2006', 'kemawi 01/05 somagede banyumas', 'muizafifudin06@gmail.com', '65', '100', '65', 'Tinggi', 'Faktor Kepribadian', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-21 09:25:39', 'baru');
INSERT INTO `t_tes_lvih` VALUES (209, 3172034504070006, 'Dhiya Nur Aini', 'c215c529-d923-440a-b340-3147c11ead20', '05-04-2007', 'Majatengah, Kemangkon', 'ainidhiyanur@gmail.com', '65', '100', '65', 'Tinggi', 'Pengalaman Masa Kecil', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-21 09:32:45', 'baru');
INSERT INTO `t_tes_lvih` VALUES (210, 2517110879, 'Syihab Ar Rasyid ', '6e230978-cd50-4aa1-a702-cb51f3c0ec5e', '30-07-2007', 'JL.KP.BARU.KUBUR.KOJA', 'syihabarrasyid@gmail.com', '92', '100', '92', 'Sangat Tinggi', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang sangat tinggi. Perasaan terisolasi dan terputus dari orang lain kemungkinan menjadi pengalaman yang dominan dan menyulitkan dalam hidup Anda saat ini. Penting untuk menyadari bahwa tingkat kerentanan ini bukanlah refleksi dari nilai diri Anda, tetapi merupakan hasil dari berbagai faktor yang dapat ditangani dengan dukungan dan strategi yang tepat.', 'Pertimbangkan untuk berkonsultasi dengan psikolog atau terapis yang dapat membantu Anda mengembangkan keterampilan sosial dan mengatasi pola pikir negatif | Bergabunglah dengan kelompok terapi atau support group untuk kesepian, yang memberikan ruang aman untuk berbagi pengalaman dan belajar dari orang lain | Tetapkan tujuan kecil namun terukur untuk interaksi sosial, seperti menghadiri satu acara sosial per minggu atau mengajak percakapan dengan satu orang baru | Praktikkan mindfulness dan self-compassion untuk mengurangi dialog internal negatif yang dapat mengisolasi Anda | Batasi penggunaan media sosial dan tingkatkan interaksi tatap muka yang bermakna | Eksplorasi terapi kognitif perilaku (CBT) untuk menantang dan mengubah pola pikir yang meningkatkan kesepian | Pertimbangkan konseling keluarga jika masalah kesepian Anda berakar pada dinamika keluarga | Jaga keseimbangan antara kebutuhan untuk waktu sendiri dan koneksi sosial yang bermakna', '2025-08-21 09:42:29', 'baru');
