INSERT INTO `t_tes_lvih` VALUES (228, 2517110215, 'ZAKI REZA ENJO WARDANA', 'ce018e7a-1440-402d-962e-7d92ac52e328', '31-03-2007', 'kecamatan singkut, kabupaten sarolangun, provinsi jambi', 'rezajaky1@gmail.com', '86', '100', '86', 'Sangat Tinggi', 'Strategi Coping', 'Anda memiliki tingkat kerentanan kesepian yang sangat tinggi. Perasaan terisolasi dan terputus dari orang lain kemungkinan menjadi pengalaman yang dominan dan menyulitkan dalam hidup Anda saat ini. Penting untuk menyadari bahwa tingkat kerentanan ini bukanlah refleksi dari nilai diri Anda, tetapi merupakan hasil dari berbagai faktor yang dapat ditangani dengan dukungan dan strategi yang tepat.', 'Pertimbangkan untuk berkonsultasi dengan psikolog atau terapis yang dapat membantu Anda mengembangkan keterampilan sosial dan mengatasi pola pikir negatif | Bergabunglah dengan kelompok terapi atau support group untuk kesepian, yang memberikan ruang aman untuk berbagi pengalaman dan belajar dari orang lain | Tetapkan tujuan kecil namun terukur untuk interaksi sosial, seperti menghadiri satu acara sosial per minggu atau mengajak percakapan dengan satu orang baru | Praktikkan mindfulness dan self-compassion untuk mengurangi dialog internal negatif yang dapat mengisolasi Anda | Batasi penggunaan media sosial dan tingkatkan interaksi tatap muka yang bermakna | Eksplorasi terapi kognitif perilaku (CBT) untuk menantang dan mengubah pola pikir yang meningkatkan kesepian | Pertimbangkan konseling keluarga jika masalah kesepian Anda berakar pada dinamika keluarga | Jaga keseimbangan antara kebutuhan untuk waktu sendiri dan koneksi sosial yang bermakna', '2025-08-22 01:20:05', 'baru');
INSERT INTO `t_tes_lvih` VALUES (229, 67794510, 'NUR INTAN WIDIANINGSIH', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '01-12-2006', 'Dk.cigobang ds.kedungoleng kec.paguyangan kab.Brebes', 'taninnurintan@gmail.com', '51', '100', '51', 'Sedang', 'Strategi Coping', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-22 01:23:23', 'baru');
INSERT INTO `t_tes_lvih` VALUES (230, 74531664, 'Fatin Amelia Salma ', '00adc9e7-7181-49b3-8b01-2a444b5c3534', '03-03-2007', 'Jl. imam Bonjol RT 01 RW 01 Sokaraja Lor ', 'amelfatin99@gmail.com', '64', '100', '64', 'Tinggi', 'Strategi Coping', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-22 01:29:48', 'baru');
INSERT INTO `t_tes_lvih` VALUES (231, 2517110345, 'Ananda Safa Ramadhani Putri', 'ea6e129b-2302-4951-afc8-a3676d110608', '21-10-2006', 'Jl. Adipati Mersi Rt 02/ Rw 04 Purwokerto Timur', 'anandasafa221@gmail.com', '55', '100', '55', 'Sedang', 'Strategi Coping', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-22 01:36:16', 'baru');
