INSERT INTO `t_tes_lvih` VALUES (336, 254110201132, 'Ratri Kinasih', '63bbc719-bef9-4643-b4a1-234af87a6b8d', '20-05-2007', 'Kalisalak RT1/RW4 Kalisalak Kebasen Banyumas', 'ratri8kinasih@gmail.com', '76', '100', '76', 'Tinggi', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-27 08:00:55', 'baru');
INSERT INTO `t_tes_lvih` VALUES (337, 254110407010, 'Deswita lila pratiwi', 'a09d4718-2359-408f-ae43-93afd060f839', '28-12-2006', 'Dusun Tanjungsari rt 04/RW 05, Prapagan, Jeruklegi ', 'deswitapratiwi456@gmail.com', '73', '100', '73', 'Tinggi', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang tinggi. Perasaan terisolasi dan terputus dari orang lain mungkin merupakan bagian yang signifikan dari pengalaman hidup Anda, terutama selama masa-masa stres atau transisi. Kerentanan pada tingkat ini dapat berdampak pada kesejahteraan mental dan fisik Anda, tetapi dengan kesadaran dan strategi yang tepat, Anda dapat mulai membangun koneksi yang lebih memuaskan.', 'Mulai jurnal untuk melacak pola kesepian Anda - kapan perasaan itu paling kuat dan apa pemicunya | Identifikasi hobi atau minat yang dapat Anda bagikan dengan orang lain untuk memfasilitasi koneksi bermakna | Pertimbangkan untuk bergabung dengan klub buku, kelas komunitas, atau kelompok hobi untuk bertemu orang dengan minat serupa | Tetapkan batasan yang sehat untuk penggunaan media sosial dan prioritaskan interaksi dunia nyata | Praktikkan keterampilan mendengarkan aktif dan berbagi diri yang tepat untuk memperdalam koneksi | Kembangkan rutinitas harian yang mencakup interaksi sosial, bahkan yang singkat seperti percakapan dengan barista | Pelajari strategi mengatasi kesepian yang lebih adaptif, seperti mencari koneksi alih-alih menarik diri | Temukan cara untuk berkontribusi pada komunitas Anda melalui kerelawanan atau proyek sosial', '2025-08-27 23:49:13', 'baru');
INSERT INTO `t_tes_lvih` VALUES (338, 254120800013, 'Umi Nurul Khanifa ', '5e0027a7-a1b1-407c-97e4-396591e45806', '09-01-2002', 'Sumbang ', 'uminurulkhanifa912@gmail.com', '88', '100', '88', 'Sangat Tinggi', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang sangat tinggi. Perasaan terisolasi dan terputus dari orang lain kemungkinan menjadi pengalaman yang dominan dan menyulitkan dalam hidup Anda saat ini. Penting untuk menyadari bahwa tingkat kerentanan ini bukanlah refleksi dari nilai diri Anda, tetapi merupakan hasil dari berbagai faktor yang dapat ditangani dengan dukungan dan strategi yang tepat.', 'Pertimbangkan untuk berkonsultasi dengan psikolog atau terapis yang dapat membantu Anda mengembangkan keterampilan sosial dan mengatasi pola pikir negatif | Bergabunglah dengan kelompok terapi atau support group untuk kesepian, yang memberikan ruang aman untuk berbagi pengalaman dan belajar dari orang lain | Tetapkan tujuan kecil namun terukur untuk interaksi sosial, seperti menghadiri satu acara sosial per minggu atau mengajak percakapan dengan satu orang baru | Praktikkan mindfulness dan self-compassion untuk mengurangi dialog internal negatif yang dapat mengisolasi Anda | Batasi penggunaan media sosial dan tingkatkan interaksi tatap muka yang bermakna | Eksplorasi terapi kognitif perilaku (CBT) untuk menantang dan mengubah pola pikir yang meningkatkan kesepian | Pertimbangkan konseling keluarga jika masalah kesepian Anda berakar pada dinamika keluarga | Jaga keseimbangan antara kebutuhan untuk waktu sendiri dan koneksi sosial yang bermakna', '2025-08-28 01:45:12', 'baru');
INSERT INTO `t_tes_lvih` VALUES (339, 254110202073, 'Mei laelatul nadia ', 'c215c529-d923-440a-b340-3147c11ead20', '14-05-2008', 'Desa Kejene, RT.31 RW.03, Kecamatan Randudongkal, Kabupaten Pemalang, Provinsi Jawa Tengah, Indonesia', 'meilaelatul890@gmail.com', '46', '100', '46', 'Sedang', 'Keterampilan Sosial', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-29 01:58:08', 'baru');
INSERT INTO `t_tes_lvih` VALUES (340, 254110303068, 'yosiku lintang sari', '591d453d-0976-40c5-863c-9e1cac0c78b9', '30-12-2007', 'kejene pemalang', 'sarilintang224@gmail.com', '59', '100', '59', 'Sedang', 'Faktor Kepribadian', 'Anda memiliki tingkat kerentanan kesepian yang sedang. Meskipun Anda mungkin mengalami kesepian dari waktu ke waktu, ini belum menjadi pengalaman yang mendominasi atau kronis. Anda kemungkinan memiliki beberapa koneksi sosial yang bermakna tetapi mungkin mengalami kesulitan dalam situasi tertentu atau periode tertentu dalam hidup Anda.', 'Prioritaskan dan investasikan waktu dalam hubungan yang sudah ada yang memberikan dukungan dan makna | Perluas jaringan sosial Anda dengan mengejar minat baru atau bergabung dengan kelompok komunitas | Kembangkan keterampilan komunikasi Anda untuk mengekspresikan kebutuhan dan perasaan dengan lebih efektif | Jadwalkan waktu sosial secara teratur - jangan menunggu sampai Anda merasa kesepian untuk mencari koneksi | Ciptakan keseimbangan yang sehat antara waktu sendiri yang bermanfaat dan interaksi sosial | Praktikkan kesadaran diri untuk mengenali kapan Anda mulai menarik diri secara sosial | Gunakan teknologi untuk mendukung, bukan menggantikan, hubungan dunia nyata | Kembangkan rutinitas self-care yang memprioritaskan kesehatan fisik dan emosional', '2025-08-29 02:17:22', 'baru');
